     3→import android.content.Context
     4→import com.google.gson.Gson
     5→import com.google.gson.reflect.TypeToken
     6→import kotlinx.coroutines.flow.MutableStateFlow
     7→import kotlinx.coroutines.flow.StateFlow
     8→import kotlinx.coroutines.flow.asStateFlow
     9→
    10→class WorkRepository(context: Context) {
    11→
    12→    private val prefs = context.getSharedPreferences("works_prefs", Context.MODE_PRIVATE)
    13→    private val gson = Gson()
    14→    private val listType = object : TypeToken<List<Work>>() {}.type
    15→
    16→    private val _works = MutableStateFlow<List<Work>>(loadAll())
    17→
    18→    private fun loadAll(): List<Work> {
    19→        val json = prefs.getString(KEY_WORKS, null) ?: return emptyList()
    20→        return gson.fromJson(json, listType) ?: emptyList()
    21→    }
    22→
    23→    private fun saveAll(works: List<Work>) {
    24→        prefs.edit().putString(KEY_WORKS, gson.toJson(works)).apply()
    25→        _works.value = works
    26→    }
    27→
    28→    fun worksForCourse(courseTitle: String): StateFlow<List<Work>> {
    29→        // Return a derived flow that filters by course; re-use _works as the source
    30→        // We expose the full list and let the ViewModel filter.
    31→        return _works.asStateFlow()
    32→    }
    33→
    34→    fun getAll(): StateFlow<List<Work>> = _works.asStateFlow()
    35→
    36→    fun insert(work: Work) {
    37→        saveAll(_works.value + work)
    38→    }
    39→
    40→    fun update(work: Work) {
    41→        saveAll(_works.value.map { if (it.id == work.id) work else it })
    42→    }
    43→
    44→    fun delete(work: Work) {
    45→        saveAll(_works.value.filter { it.id != work.id })
    46→    }
    47→
    48→    companion object {
    49→        private const val KEY_WORKS = "all_works"
    50→
    51→        @Volatile
    52→        private var INSTANCE: WorkRepository? = null
    53→
    54→        fun getInstance(context: Context): WorkRepository =
    55→            INSTANCE ?: synchronized(this) {
    56→                WorkRepository(context.applicationContext).also { INSTANCE = it }
    57→            }
    58→    }
    59→}
    60→

